#include <vector>
#include <string>
#include <algorithm>

using namespace std;

long long compute_lcp(const string& a, const string& b) {
    long long len = 0;
    while (len < a.length() && len < b.length() && a[len] == b[len]) {
        ++len;
    }
    return len;
}

vector<long long> solve(vector<string> words) {
    int n = words.size();
    if (n == 1) {
        return {0};
    }

    vector<long long> lcp(n-1, 0);
    for (int i = 0; i < n-1; ++i) {
        lcp[i] = compute_lcp(words[i], words[i+1]);
    }

    vector<long long> prefix_max(n-1, 0);
    prefix_max[0] = lcp[0];
    for (int i = 1; i < n-1; ++i) {
        prefix_max[i] = max(prefix_max[i-1], lcp[i]);
    }

    vector<long long> suffix_max(n-1, 0);
    suffix_max[n-2] = lcp[n-2];
    for (int i = n-3; i >= 0; --i) {
        suffix_max[i] = max(suffix_max[i+1], lcp[i]);
    }

    vector<long long> answer(n, 0);

    for (int i = 0; i < n; ++i) {
        if (n == 2) {
            answer[i] = 0;
        } else {
            if (i == 0) {
                if (n-2 >= 1) {
                    answer[i] = suffix_max[1];
                } else {
                    answer[i] = 0;
                }
            } else if (i == n-1) {
                if (n-3 >= 0) {
                    answer[i] = prefix_max[n-3];
                } else {
                    answer[i] = 0;
                }
            } else {
                long long left_max = 0;
                if (i-2 >= 0) {
                    left_max = prefix_max[i-2];
                }
                long long right_max = 0;
                if (i+1 <= n-2) {
                    right_max = suffix_max[i+1];
                }
                long long max_without_i = max(left_max, right_max);
                long long new_lcp = compute_lcp(words[i-1], words[i+1]);
                answer[i] = max(max_without_i, new_lcp);
            }
        }
    }

    return answer;
}

